mapper.select:
select a.*,cast(u.user_name as char) user_name,u.headimgurl,u.source,p.status promiseStatus,u.cpc from lkt_mch a left join lkt_user as u on a.user_id = u.user_id left join lkt_mch_promise p on p.mch_id=a.id
a.collection_num ${collection_num_sort}, a.add_time ${add_time_sort},
limit #{pageStart},#{pageEnd}

select ifnull(sum(money),0) from lkt_mch_order_record

    store_id = #{storeId} and recycle=0 and mch_id=#{mchId}
    
        
            and DATE_FORMAT( count_day, '%Y-%m' ) = #{date}
        
        
            and DATE_FORMAT( count_day, '%Y-%m-%d' ) = #{date}

select ifnull(sum(order_num),0) from lkt_mch_order_record

    store_id = #{storeId} and recycle=0 and mch_id=#{mchId}
    
        
            and DATE_FORMAT( count_day, '%Y-%m' ) = #{date}
        
        
            and DATE_FORMAT( count_day, '%Y-%m-%d' ) = #{date}

select u.user_name,u.headimgurl as img,a.money from lkt_mch_buy_power a
left join lkt_user u on u.user_id = a.user_id
where a.store_id = #{storeId} and a.recycle=0 and a.mch_id=#{mchId}
order by a.money desc;

select a.product_title,a.imgurl,(a.volume+a.real_volume) as volume,a.id as pid from lkt_product_list a
where a.store_id = #{storeId} and a.recycle=0 and a.mch_id=#{mchId}
order by volume desc;

SELECT z.id, z.name, z.add_date, z.upNum, z.lowerNum, z.orderNum, z.settlementPrice FROM ( SELECT b.id, b.name, a.add_date, ( SELECT COUNT(1) FROM lkt_product_list AS p WHERE p.gongyingshang = #{supplierId} AND p.mch_id = b.id AND p.status = 2 AND p.recycle = 0 ) AS upNum, ( SELECT COUNT(1) FROM lkt_product_list AS p WHERE p.gongyingshang = #{supplierId} AND p.mch_id = b.id AND p.status = 3 AND p.recycle = 0 ) AS lowerNum, ( SELECT COUNT(DISTINCT o.sNo) FROM lkt_order o RIGHT JOIN lkt_order_details d ON o.sNo = d.r_sNo LEFT JOIN lkt_product_list p ON d.p_id = p.id WHERE p.gongyingshang = #{supplierId} AND p.mch_id = b.id AND o.is_lssued = 1 ) AS orderNum, IFNULL( ( SELECT SUM(d.supplier_settlement) FROM lkt_order o RIGHT JOIN lkt_order_details d ON o.sNo = d.r_sNo LEFT JOIN lkt_product_list p ON d.p_id = p.id WHERE p.gongyingshang = #{supplierId} AND p.mch_id = b.id AND o.settlement_status = 1 AND o.is_lssued = 1 ), 0 ) AS settlementPrice, ROW_NUMBER() OVER ( PARTITION BY b.id ORDER BY a.add_date DESC ) AS rn FROM lkt_product_list a LEFT JOIN lkt_mch b ON a.mch_id = b.id WHERE a.store_id = #{storeId} AND a.gongyingshang = #{supplierId} AND a.recycle = 0 AND a.mch_id != 0
AND b.name LIKE CONCAT('%', #{mchName}, '%')
AND a.add_date >= #{startTime}
AND a.add_date <= #{endTime}
ORDER BY a.add_date DESC limit #{pageStart},#{pageEnd} ) as z WHERE z.rn = 1

SELECT sub.* FROM ( SELECT m.*, ( SELECT COUNT(DISTINCT p2.id) FROM lkt_product_list p2 WHERE p2.mch_id = m.id AND p2.status = 2 AND p2.mch_status = 2 ) AS pro_num, ( SELECT COUNT(DISTINCT c2.id) FROM lkt_user_collection c2 WHERE c2.mch_id = m.id AND c2.type = 1 AND c2.user_id = #{userId} ) AS is_collect, ( SELECT COUNT(DISTINCT luc2.id) FROM lkt_user_collection luc2 WHERE luc2.mch_id = m.id AND luc2.type = 1 ) AS collectionNum, ROW_NUMBER() OVER ( PARTITION BY m.id ORDER BY m.id DESC ) AS rn FROM lkt_mch m WHERE m.store_id = #{storeId} AND m.review_status = 1 AND m.recovery = 0
AND m.name LIKE CONCAT('%',#{mchName},'%')
) sub WHERE sub.rn = 1 ORDER BY sub.id DESC LIMIT #{pageStart}, #{pageEnd}
